async function bitcoin_newaddress () {
  try {
    const { stdout } = await btcRpc('getnewaddress')
    return { status: 'success', data: stdout.trim() }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function get_btc_balance () {
  try {
    const { stdout } = await btcRpc('getbalance')
    return { status: 'success', data: { btc: parseFloat(stdout.trim()) } }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}


async function get_ln_balance (data = {}) {
  const nodeId = data.userId || 'node4' // Use userId as the nodeId
  try {
    const { stdout } = await lnRpc(nodeId, 'listfunds')
    const parsed = JSON.parse(stdout)
    const outputs = parsed.outputs || []

    const onchain_msat = outputs
      .filter(o => o.status === 'confirmed')
      .reduce((acc, o) => acc + (o.amount_msat || 0), 0)

    const channel_msat = (parsed.channels || [])
      .reduce((acc, c) => acc + (c.our_amount_msat|| 0), 0)
    
    const total_msat = onchain_msat + channel_msat
    const total_sats = total_msat / 1000

    return {
      status: 'success',
      data: {
        sats: total_sats,
        btc: total_sats / 1e8,
        raw: parsed 
      }
    }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function sync_wallet_balances (data = {}) {
  const nodeId = data.userId || 'node4'
  try {
    // Run in parallel
    const [btcResult, lnResult] = await Promise.all([
      get_btc_balance(), // btc balance isn't user-specific in this setup
      get_ln_balance({ userId: nodeId })
    ])

    if (btcResult.status === 'error' || lnResult.status === 'error') {
      throw new Error(`BTC Error: ${btcResult.error} || LN Error: ${lnResult.error}`)
    }

    return {
      status: 'success',
      data: {
        btc_balance: btcResult.data.btc,
        ln_balance_sats: lnResult.data.sats
      }
    }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

