async function validate_btc_payment (data = {}) {
  const { tx_id, amount, min_conf } = data
  if (!tx_id) return { status: 'error', error: 'tx_id is required' }
  
  try {
    const { stdout } = await btcRpc('gettransaction', [tx_id, true]) // true for verbose
    const tx = JSON.parse(stdout)

    // Check confirmations
    const confirmations = tx.confirmations || 0
    if (confirmations < (min_conf || 1)) {
      return { status: 'pending', data: { confirmations, tx } }
    }

    const receivedAmount = (tx.details || [])
      .filter(d => d.category === 'receive')
      .reduce((acc, d) => acc + d.amount, 0)

    if (amount && receivedAmount !== parseFloat(amount)) {
      return { status: 'error', error: `Amount mismatch: expected ${amount}, got ${receivedAmount}` }
    }
    
    return { status: 'success', data: { confirmations, receivedAmount, tx } }
    
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function send_btc_onchain (data = {}) {
  const { recipient_address, amount_btc, note, fee_rate_sats_per_vb } = data;
  if (!recipient_address || !amount_btc) {
    return { status: 'error', error: 'recipient_address and amount_btc are required' };
  }

  // 1 sat/vB = 1000 sats/kvB = 0.00001000 BTC/kB
  // Bitcoin Core's 'sendtoaddress' fee_rate is in sat/vB
  // So we just pass fee_rate_sats_per_vb directly
  
  try {
    const params = [
      `address=${recipient_address}`,
      `amount=${amount_btc}`,
      `comment="${note || ''}"`,
      `comment_to="${note || ''}"`,
      'replaceable=true' 
    ];

    // Only add the fee_rate param if the user provided one
    if (fee_rate_sats_per_vb) {
      // The 'sendtoaddress' RPC accepts fee_rate in sat/vB!
      params.push(`fee_rate=${fee_rate_sats_per_vb}`);
    }

    // Call btcRpc with named = true
    const { stdout } = await btcRpc('sendtoaddress', params, true);
    const tx_id = stdout.trim();
    
    return { status: 'success', data: { tx_id } };

  } catch (err) {
    return { status: 'error', error: err.message };
  }
}


async function estimate_btc_fee (data = {}) {
  const priority = data.priority || 'medium'
  const blockTargets = {
    'high': 2,
    'medium': 6,
    'low': 100
  }
  const target = blockTargets[priority] || 6

  try {
    const { stdout } = await btcRpc('estimatesmartfee', [target])
    const parsed = JSON.parse(stdout)

    // Check if the feerate is available
    if (parsed.feerate) {
      return { 
        status: 'success', 
        data: { 
          feerate_btc_per_kb: parsed.feerate,
          blocks: parsed.blocks || target
        } 
      }
    }

    // *** FALLBACK ***
    // If feerate is missing (e.g., regtest), return a default
    console.log(`estimatesmartfee returned no feerate. Using fallback.`);
    const fallbackFee = 0.00001000 // A default of 10 sats/vB (in BTC/kB)
    return {
      status: 'success',
      data: {
        feerate_btc_per_kb: fallbackFee,
        blocks: target,
        note: 'Using regtest fallback fee'
      }
    }
    
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function convert_btc_to_usd (data = {}) {
  const amount_btc = data.amount_btc
  if (amount_btc === undefined) {
    return { status: 'error', error: 'amount_btc is required' }
  }

  // Using CoinGecko's free API
  const url = 'https://api.coingecko.com/api/v3/simple/price?ids=bitcoin&vs_currencies=usd'

  try {
    // Using fetch() which is available globally in Node.js v18+
    const response = await fetch(url)
    
    if (!response.ok) {
      throw new Error(`API request failed with status ${response.status}`)
    }

    const parsed = await response.json()

    // CoinGecko's response format is { "bitcoin": { "usd": 65000.12 } }
    if (!parsed.bitcoin || !parsed.bitcoin.usd) {
      throw new Error('Failed to parse price from API response')
    }

    const rate = parseFloat(parsed.bitcoin.usd)
    const usd_value = rate * amount_btc
    
    return {
      status: 'success',
      data: {
        btc_amount: amount_btc,
        usd_value: usd_value,
        rate_per_btc: rate
      }
    }
  } catch (e) {
    return { status: 'error', error: `Price API request failed: ${e.message}` }
  }
}

async function bitcoin_mine_blocks (data = {}) {
  const num_blocks = data.num_blocks || 1
  
  try {
    const { stdout: address } = await btcRpc('getnewaddress', ['"miner-reward"'])
    
    const { stdout: block_hashes } = await btcRpc('generatetoaddress', [num_blocks, address.trim()])
    
    return {
      status: 'success',
      data: {
        blocks_mined: num_blocks,
        block_hashes: JSON.parse(block_hashes) 
      }
    }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

// -----------------------------------------------------------------------------
// 🔄 WebSocket handler
// -----------------------------------------------------------------------------
async function handleMessage (msg, ws, server) {
  const [by, to, mid] = msg.head || []
  const intent = msg.type
  const data = msg.data 

  console.log(`📩 Received from ${by}:`, intent, data || '')

  if (intent === 'daemon-stop') {
    console.log('🚨 Stopping backend daemon as requested...')
    // Handle graceful shutdown if needed
  }

  const actions = {
    // Core functions 
    'lightning-getinfo': lightning_getinfo,
    'lightning-listfunds': lightning_listfunds_raw, 
    'bitcoin-newaddress': bitcoin_newaddress,
    
    'get_btc_balance': get_btc_balance,
    'get_ln_balance': get_ln_balance,
    'sync_wallet_balances': sync_wallet_balances,
    'convert_btc_to_usd': convert_btc_to_usd,
    'estimate_btc_fee': estimate_btc_fee,
    'get_tx_details_from_btcnode': get_tx_details_from_btcnode,
    'get_tx_details_from_lnnode': get_tx_details_from_lnnode,
    'list_btc_transactions': list_btc_transactions,
    'list_ln_invoices': list_ln_invoices,


    'validate_btc_payment': validate_btc_payment, 
    'validate_ln_payment': validate_ln_payment,
    'send_btc_onchain': send_btc_onchain,      
    'send_ln_payment': send_ln_payment,        
    'get_ln_payment_status': get_ln_payment_status,  
    'bitcoin_mine_blocks': bitcoin_mine_blocks 
  }

  const fn = actions[intent]
  if (!fn) {
    // NEW: Handle unknown actions gracefully
    return ws.send(JSON.stringify({
      head: ['backend', by, mid],
      type: `${intent}:response`,
      data: { status: 'error', error: `Unknown action: ${intent}` }
    }))
  }

  // Pass the 'data' payload to the action function
  const payload = await fn(data) 
  
  // Send the response
  ws.send(JSON.stringify({
    head: ['backend', by, mid],
    type: `${intent}:response`,
    data: payload
  }))
}

// -----------------------------------------------------------------------------
// 🚀 WebSocket server setup
// -----------------------------------------------------------------------------
const wss = new WebSocketServer({ port: Number(WS_PORT) }) // Removed 'a ='
console.log(`🚀 Backend daemon listening on ws://localhost:${WS_PORT}`)

wss.on('connection', (ws, req) => {
  console.log('client connected:', req.socket.remoteAddress)
  ws.on('message', async (raw) => {
    try {
      const msg = JSON.parse(raw.toString())
      await handleMessage(msg, ws, wss)
    } catch (err) {
      console.error('Message error:', err.message)
      ws.send(JSON.stringify({ type: 'error', data: { error: err.message } }))
    }
  })
  ws.on('close', () => console.log('client disconnected'))
})